7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  component: 30,
13	  rune: 30,
14	};
15	
16	const calculateBasePremium = (items: Item[]): number => {
17	  return items.reduce(
18	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
19	    0
20	  );
21	};
22	
23	const getProcessingFee = (itemCount: number): number => {
24	  if (itemCount === 0) return 0;
25	  if (itemCount === 1) return 5;
26	  if (itemCount === 2) return 10;
27	  return 5;
28	};
29	
30	export function quote(items: Item[]): number {
31	  if (items.length === 0) return 0;
32	  return calculateBasePremium(items) + getProcessingFee(items.length);
33	}
